// Global Tracking States
let currentCategory = '';
let currentQuestionIndex = 0;
let correctCount = 0;
let wrongCount = 0;

// FUNCTION 1: Injects Massive Text Content (Encyclopedia View)
function showIntro(key) {
    document.querySelectorAll('.nav-btn').forEach(btn => btn.classList.remove('active'));
    
    const targetBtn = document.getElementById(`btn-${key}`);
    if(targetBtn) targetBtn.classList.add('active');

    const box = document.getElementById("dynamic-box");
    const data = introData[key];

    let paragraphHTML = '';
    data.paragraphs.forEach(p => {
        paragraphHTML += `<p class="essay-paragraph">${p}</p>`;
    });

    box.innerHTML = `
        <h1 class="essay-title">${data.title}</h1>
        ${paragraphHTML}
        <div style="margin-top: 40px; border-top: 1px solid #cbd5e1; padding-top: 20px; font-style: italic; color:#64748b; font-size:14px;">
            📌 Source reference: Global Cricket Constitution & Institutional Data Archives.
        </div>
    `;

    document.getElementById("char-speech").innerText = `Now hosting the primary text array for: ${data.title}. Use scrollbar to read full dossier.`;
}

// FUNCTION 2: Injects and Boots Quiz Interface (Wipes out intro blocks entirely)
function startQuiz(category) {
    currentCategory = category;
    currentQuestionIndex = 0;
    correctCount = 0;
    wrongCount = 0;

    document.querySelectorAll('.nav-btn').forEach(btn => btn.classList.remove('active'));
    const targetBtn = document.getElementById(`btn-${category}`);
    if(targetBtn) targetBtn.classList.add('active');

    const box = document.getElementById("dynamic-box");
    
    box.innerHTML = `
        <h3 class="quiz-header">${category.toUpperCase()} Live Evaluation Championship</h3>
        <p class="question-count" id="q-counter"></p>
        <div class="question-text" id="q-txt"></div>
        
        <div class="options-grid">
            <button class="opt-btn" onclick="evaluateSelection(0)"></button>
            <button class="opt-btn" onclick="evaluateSelection(1)"></button>
            <button class="opt-btn" onclick="evaluateSelection(2)"></button>
            <button class="opt-btn" onclick="evaluateSelection(3)"></button>
        </div>
        
        <button class="next-action-btn" id="nxt-question-btn" onclick="shiftNext()">Next Question &rarr;</button>
    `;

    renderQuestionSheet();
}

function renderQuestionSheet() {
    const qCounter = document.getElementById("q-counter");
    const qTxt = document.getElementById("q-txt");
    const options = document.querySelectorAll(".opt-btn");
    const nxtBtn = document.getElementById("nxt-question-btn");
    const speech = document.getElementById("char-speech");

    let currentList = quizData[currentCategory];
    qCounter.innerText = `Question ${currentQuestionIndex + 1} of ${currentList.length}`;
    
    let activeQuestion = currentList[currentQuestionIndex];
    qTxt.innerText = activeQuestion.q;

    options.forEach((btn, index) => {
        btn.innerText = activeQuestion.options[index];
        btn.style.backgroundColor = "#f8fafc";
        btn.style.borderColor = "#e2e8f0";
        btn.style.color = "#334155";
        btn.disabled = false;
    });

    nxtBtn.style.display = "none";
    speech.innerText = `Live testing active on category: ${currentCategory.toUpperCase()}. Select option.`;
}

function evaluateSelection(index) {
    const options = document.querySelectorAll(".opt-btn");
    const nxtBtn = document.getElementById("nxt-question-btn");
    const speech = document.getElementById("char-speech");
    
    let activeQuestion = quizData[currentCategory][currentQuestionIndex];
    options.forEach(btn => btn.disabled = true);

    if(index === activeQuestion.correct) {
        options[index].style.backgroundColor = "#dcfce7";
        options[index].style.borderColor = "#22c55e";
        options[index].style.color = "#15803d";
        speech.innerText = "Target hit! Clean logic. Answer is correct! 🎉";
        correctCount++;
    } else {
        options[index].style.backgroundColor = "#fee2e2";
        options[index].style.borderColor = "#ef4444";
        options[index].style.color = "#b91c1c";
        
        options[activeQuestion.correct].style.backgroundColor = "#dcfce7";
        options[activeQuestion.correct].style.borderColor = "#22c55e";
        options[activeQuestion.correct].style.color = "#15803d";
        speech.innerText = "Stumps rattled! Incorrect choice. Sahi jawab ko green highlight kiya gaya hai.";
        wrongCount++;
    }

    nxtBtn.style.display = "block";
}

function shiftNext() {
    currentQuestionIndex++;
    if(currentQuestionIndex < quizData[currentCategory].length) {
        renderQuestionSheet();
    } else {
        const box = document.getElementById("dynamic-box");
        const speech = document.getElementById("char-speech");
        
        box.innerHTML = `
            <div class="results-card">
                <h2>📊 Live Performance Analytics Card</h2>
                <p>The processing module has evaluated your response pattern data.</p>
                <div class="score-flex">
                    <div class="score-pane good">✅ Corrected Units: ${correctCount}</div>
                    <div class="score-pane bad">❌ Incorrect Units: ${wrongCount}</div>
                </div>
                <h3>Final Grade: ${correctCount} / ${quizData[currentCategory].length} Correct</h3>
                <button class="nav-btn" style="margin-top:25px; background-color:#38bdf8; color:#0f172a; font-weight:bold; padding: 12px 30px;" onclick="startQuiz('${currentCategory}')">Re-enter Simulation 🔄</button>
            </div>
        `;
        speech.innerText = `Evaluation complete. Final score register updated with value: ${correctCount}.`;
    }
}

// System Boot configuration (Default landing setup)
showIntro('general');